using System;

class NumberList
{
    private int[] numbers = new int[5];

    public int this[int index]
    {
        get
        {
            if (index >= 0 && index < numbers.Length)
            {
                return numbers[index];
            }
            throw new IndexOutOfRangeException("İndeks sərhəddən kənardır.");
        }
        set
        {
            if (index >= 0 && index < numbers.Length)
            {
                numbers[index] = value;
            }
            else
            {
                throw new IndexOutOfRangeException("İndeks sərhəddən kənardır.");
            }
        }
    }
}

class Program
{
    static void Main(string[] args)
    {
        NumberList list = new NumberList();
        list[0] = 10; // set istifadə olunur
        list[1] = 20;
        Console.WriteLine($"Elementlər: {list[0]}, {list[1]}"); // get istifadə olunur
    }
}
// Output:
// Elementlər: 10, 20

